import { MakeLogicType, afterMount, kea, path } from 'kea'
import { loaders } from 'kea-loaders'

import { ApiRequest } from 'lib/api'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface exceptionIngestionLogicValues {
    hasSentExceptionEvent: boolean | undefined
    hasSentExceptionEventLoading: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface exceptionIngestionLogicActions {
    loadExceptionIngestionState: () => any
    loadExceptionIngestionStateFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadExceptionIngestionStateSuccess: (
        hasSentExceptionEvent: boolean,
        payload?: any
    ) => {
        hasSentExceptionEvent: boolean
        payload?: any
    }
}

export type exceptionIngestionLogicType = MakeLogicType<exceptionIngestionLogicValues, exceptionIngestionLogicActions>

export const exceptionIngestionLogic = kea<exceptionIngestionLogicType>([
    path(['products', 'error_tracking', 'components', 'SetupPrompt', 'exceptionIngestionLogic']),
    loaders({
        hasSentExceptionEvent: {
            __default: undefined as boolean | undefined,
            loadExceptionIngestionState: async (): Promise<boolean> => {
                const response = await new ApiRequest()
                    .errorTrackingIssuesExists()
                    .get()
                    .catch(() => null)

                return response?.exists === true
            },
        },
    }),

    afterMount(({ actions }) => {
        actions.loadExceptionIngestionState()
    }),
])
